INSERT INTO `tcf_ce_exams` (`id`, `slug`, `title`, `subtitle`, `intro_html`, `visibility`, `is_published`, `duration_seconds`, `published_at`, `created_by`, `created_at`, `updated_at`) VALUES (4,'comprehension-ecrite-1-561827','Compréhension Écrite 1','Testez vos compétences en compréhension écrite française (quiz)',NULL,'gratuit',1,3600,'2026-07-22 23:02:08',NULL,'2026-07-22 23:02:08','2026-07-22 23:02:08');
INSERT INTO `tcf_ce_exams` (`id`, `slug`, `title`, `subtitle`, `intro_html`, `visibility`, `is_published`, `duration_seconds`, `published_at`, `created_by`, `created_at`, `updated_at`) VALUES (5,'comprehension-ecrite-2-974537','Compréhension Écrite 2','Épreuve de compréhension écrite — 39 questions',NULL,'gratuit',1,3600,'2026-07-22 23:02:08',NULL,'2026-07-22 23:02:08','2026-07-22 23:02:08');
INSERT INTO `tcf_ce_exams` (`id`, `slug`, `title`, `subtitle`, `intro_html`, `visibility`, `is_published`, `duration_seconds`, `published_at`, `created_by`, `created_at`, `updated_at`) VALUES (6,'comprehension-ecrite-3-644367','Compréhension Écrite 3','Épreuve de compréhension écrite — 31 questions',NULL,'gratuit',1,3600,'2026-07-22 23:02:08',NULL,'2026-07-22 23:02:08','2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (470,4,1,'Maman. Je fais mes devoirs de mathématiques chez Louise. Je rentre à 21 heures. Bises et à ce soir. Patrick','Qu\'est-ce que Patrick fait chez Louise ?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (471,4,2,'Attention. Cette semaine, l\'accueil de l\'université est fermé lundi toute la journée et vendredi après-midi.','A quoi sert cette affiche ?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (472,4,3,'Alen, bonjour, C\'est d\'accord, RV avec les copines chez-moi le 30 avril pour déjeuner Bisous CANADA Yvette','Quelles sont les relations entre Aline et Yvette ?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (473,4,4,'Nous informons notre aimable clientèle que nous sommes actuellement en vacances jusqu\'au dimanche 1er septembre. Nous aurons le plaisir de vous retrouver à partir du 2. Le magasin ouvrira comme tous les lundis à 11 h. Bonnes vacances à tous.','Qu\'apprend-on sur le magasin ?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (474,4,5,'Salut Paul, Je t’écris du Canada. J’ai rencontré un étudiant mexicain. Je suis contente de parler ma langue avec lui, car l’Espagne me manque beaucoup ! En juin, nous suivons ensemble une formation en Italie. Je t’appelle bientôt. Bisous, Elsa','Quelle est la nationalité d\'Elsa ?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (475,4,6,'Nous avons prévu quelques réparations dans l\'appartement à la fin de la semaine. Veuillez nous excuser pour le bruit. M. et Mme Garnier, 7 avenue du Général Leclerc Appt. 307','Qu’est-ce que M. et Mme Garnier écrivent à leurs voisins ?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (476,4,7,'Chère Cathy, Après six mois de travaux, Pierre et moi avons quitté la maison de ses parents et nous sommes enfin installés chez nous ! Nous fêtons l’évènement le dimanche 23 juin à partir de 19 h 30. J’espère que tu pourras venir ! Lésa','Qu’est-ce que Lésa va fêter ?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (477,4,8,'Un poste est libre dans votre association ? Le site www.place-publique.fr vous propose de publier une annonce. Envoyez-nous la description du poste, le salaire et vos coordonnées. Votre annonce sera visible pendant un mois.','Que peuvent faire les associations sur ce site Internet ?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (478,4,9,'Madame, Nous avons bien reçu votre demande de remboursement pour un billet de train (voyage professionnel). Vous nous avez envoyé le ticket de carte bancaire, mais nous avons aussi besoin d’une attestation de votre employeur. Merci de nous l’adresser par courrier postal ou sous format électronique. Cordialement, Le service financier.','Quel document doit fournir la femme ?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (479,4,10,'Semaine du 6 au 10 septembre : Le restaurant universitaire vous propose des recettes régionales variées au tarif normal. Rendez-vous de 11h15 à 13h dans la salle du premier étage. Bon appétit !','Que propose le restaurant du 6 au 10 septembre ?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (480,4,11,'Vous voulez faire connaître votre entreprise ? Nous vous proposons de très bons prix pour mettre une annonce sur notre site Internet. Envoyez-nous votre texte, nous vous contacterons pour vous informer sur nos prix.','Que propose cette annonce aux entreprises ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (481,4,12,'La librairie des Orgues à Paris a récolté 9000 euros de ses clients afin de financer son déménagement. Un résultat inespéré qui a permis à la librairie de s’agrandir. Lors de l’inauguration, la libraire a offert un verre à ses généreux donateurs. En fonction du montant de leur participation, ils ont reçu un livre de leur choix ou ont obtenu le statut de client d’or, signifié par une plaque à leur nom sur le mobilier de la librairie.','Pourquoi la librairie a-t-elle récolté de l’argent ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (482,4,13,'Madame Guilbert, L’imprimante de mon bureau ne fonctionne pas. Mes consultations commencent demain à 14 h. Pourriez-vous commander rapidement du papier et de l’encre, s’il vous plaît ? Merci, Docteur Philippe','Que doit faire Madame Guilbert ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (483,4,14,'Cher Paul, Je suis désolée de t’avoir laissé sans nouvelle. Je pensais t’écrire de Fès, mais notre séjour ne s’est pas déroulé comme nous l’espérions. Nous avons passé trois nuits supplémentaires à Tanger à cause d’un problème technique sur une de nos lignes touristiques. Nous avons aussi annulé le rendez-vous prévu aujourd’hui avec notre client de Casablanca, car nous avons dû nous rendre à Marrakech pour régler les frais occasionnés par cet incident. Nous rentrons demain à Paris. Bises','Dans quelle ville se trouve Mathilde d’après cette lettre ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (484,4,15,'Olivier Pollet, co-fondateur d\'Escursia, veut développer le tourisme scientifique. C\'est un tourisme permettant de découvrir et d\'apprendre sur la nature, la faune et la flore, au cours de treks ou de randonnées guidées par des accompagnateurs scientifiques professionnels désirant faire partager leurs connaissances. Ces séjours sont ouverts à tous les publics et pour y prendre part, il ne faut pas nécessairement disposer d\'une excellente condition physique, il faut juste une pointe de curiosité et le sens de l\'observation.','Quelle est la particularité du tourisme scientifique ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (485,4,16,'Les gardes-chasse d’Orly ont lancé une campagne de capture des lapins vivant sur l’aéroport, afin de les expatrier vers le sud de la France, dont la faune et la flore ont été dévastées par les grands incendies de l’été dernier. Le lapin élevé au kérosène va donc se refaire une santé auprès des romarins et des thyms de Provence. On connait des riverains qui aimeraient bien être des petits lapins !','Qu’est-il arrivé aux lapins de l’aéroport d’Orly ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (486,4,17,'Il y a beaucoup d’avantages démontrés par les faits à choisir la Suisse pour y effectuer ses études ou une partie de celles-ci. La qualité de vie, celle des formations dispensées même si elles sont souvent chères, la situation géographique et l’ouverture internationale du pays… Du côté des défauts, mentionnons le fait que toutes les filières et formations ne sont pas représentées, ce qui est le cas dans la plupart des petits pays.','Quel avantage présente l’enseignement supérieur dans ce pays ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (487,4,18,'On croyait leur métier en voie de disparition et pourtant le nombre de secrétaires a doublé en vingt ans. Ceux qui avaient dit que l’informatique les remplacerait se sont trompés. Au contraire, elles n’ont jamais été aussi recherchées. Leurs tâches classiques ont tendance à diminuer au profit de nouvelles responsabilités. Elles sont de moins en moins rattachées à une seule personne, mais à une équipe. Toutefois, malgré l’importance qu’elles ont prise, elles souffrent toujours d’un certain manque de reconnaissance.','Aujourd’hui, quel est l’inconvénient du métier de secrétaire ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (488,4,19,'L\'anglais est arrivé au vingtième siècle, à la première place du palmarès des langues internationales. Près de la moitié de l\'humanité est concernée par cette langue, car elle est quasi obligatoire dans de nombreux secteurs d’activité. Pourtant, cette situation a des limites et l’anglais devra faire face à la progression d’autres langues dans les années à venir. Les raisons sont la montée en puissance économique et industrielle de grands pays émergents, le développement d’échanges régionaux et ceux entre pays voisins.','Que dit-on de la langue anglaise dans cet article ?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (489,4,20,'Job d’été, la première expérience. Quand une entreprise fait appel pour la première fois à un jeune, elle n’a pas d’attente vis-à-vis de ses compétences professionnelles, c’est donc sur son comportement que vont se porter ses critères d’évaluation. Même saisonnier. Il faut montrer qu’on a vraiment envie de décrocher un job. Les jeunes sans expérience ont tout intérêt à parler de leur passion et à démontrer leur motivation. Pour un employeur, c’est ce qui reste souvent le critère le plus important.','Selon l’article, que faut-il faire pour trouver un job d’été ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (490,4,21,'Le jour viendra où un fonds de pension ou un groupe alimentaire mondial investira dans l\'entreprise d\'un cuisinier reconnu pour orchestrer son développement international. Bien sûr, on ne peut qu\'avoir de la nostalgie pour les temps héroïques ou une bande de copains inventait les codes de la nouvelle cuisine. Aujourd\'hui, n\'importe quel jeune cuisinier est prêt à payer très cher pour le privilège d\'un stage de six mois chez un « Grand chef ». Il rentabilisera vite cet investissement en s\'autoproclamant élève de, car les marques des grands chefs ne cessent de prendre de la valeur.','Qu’apprend-on sur les grands chefs ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (491,4,22,'Non, Maupassant n\'est pas qu\'un écrivain pour cours de français. Comme tout bon auteur culte, ses thématiques sont percutantes, grinçantes, toujours d\'actualité. Et tellement vraies dans le fond : hypocrisie de la bourgeoisie, monde paysan décrit sans artifice, rapports humains aliénés par le contexte social et culturel... Du pain bénit pour les auteurs de « Chez Maupassant », une collection de huit téléfilms tirés des contes et nouvelles du grand Guy.','Que présente l’auteur de l’article ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (492,4,23,'Elle devait être démolie et un nouveau lieu de culte reconstruit à l’arrière de l’église actuelle, le long du boulevard. Le projet, qui prévoyait la restructuration complète de l’îlot avec la création de logements sociaux, ne verra finalement pas le jour. La Ville et le diocèse ont pris la décision de conserver l’église Sainte-Madeleine considérant avec certains experts que sa démolition aurait causé la perte regrettable d’un élément important du patrimoine nantais. Des travaux d’urgence vont être réalisés avant le lancement d’un véritable programme de restauration et de mise en valeur du bâtiment.','Selon cet article, quelle décision a été prise ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (493,4,24,'L’insecte pourrait devenir une solution économique à notre appétit de protéines. Vous attrapez trois grillons déshydratés et les enfournez dans votre bouche : vous voilà mangeur d’insectes. Vous contribuez à la préservation des ressources. En effet, il faut 10 kg de céréales pour produire 1 kg de bœuf ou 9 kg d’insectes. La demande mondiale de protéines va doubler et les insectes, c’est riche en protéines. Depuis l’an dernier, la communauté européenne subventionne les projets de recherche dans ce secteur. Les grands groupes alimentaires s’intéressent au sujet, mais attendent que les citoyens soient psychologiquement prêts.','Qu’apprend-on sur la production d’insectes ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (494,4,25,'Ces dernières années, les nouvelles versions de films à succès se sont multipliées et ce mouvement ne semble pas près de s’arrêter, comme si l’industrie cinématographique ne parvenait plus à inventer de nouvelles histoires, de nouveaux concepts qui pourraient éveiller la curiosité d’un large public. Pourtant, de nouvelles idées, de nouvelles sensibilités, il y en aura toujours, encore faut-il qu’elles trouvent un relais financier pour voir le jour. Et l’industrie cinématographique hésite à investir dans du « neuf », alors elle se tourne vers les valeurs sûres des succès passés.','Quelle constatation ce journaliste fait-il sur le cinéma contemporain ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (495,4,26,'Le droit à l’oubli sur internet est fondamental. Aujourd’hui, internet nous expose à des risques, en mettant à portée d’institutions ou d’entreprises des informations personnelles que nous avons oubliées ou que nous souhaitons oublier. Or l’oubli, autant que la mémoire, est essentiel à l’humain pour être capable d’agir et de fonctionner dans le présent. Un spécialiste de la question propose une solution. Si les gens ont envie de sauvegarder des informations les concernant, ils y attacheront une date d’expiration. Les citoyens doivent choisir eux-mêmes ce qui de leurs informations personnelles, sera retenu ou effacé, cela ne doit pas résulter du choix de grosses sociétés ou de gouvernements.','Pourquoi le droit à l’oubli sur internet est-il important ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (496,4,27,'Une étude récente révèle que la concentration de déchets plastiques flottant à la surface du pacifique nord a été multipliée par cent en quarante ans. Ce constat, émis par les pêcheurs en haute mer, est alarmant, car cette pollution a des conséquences écologiques. La gigantesque plaque de déchets flottant sur l’océan pacifique, épais par endroits de plusieurs dizaines de mètres, constitue un milieu favorable à la reproduction d’une espèce d’araignée d’eau. Cet insecte est en train de se multiplier dans le pacifique nord. Si la densité des plastiques continue à augmenter, certaines espèces pourraient continuer à se multiplier, risquant de déséquilibrer l’écosystème du Pacifique.','Pourquoi le droit à l’oubli sur internet est-il important ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (497,4,28,'Les jeunes du lycée professionnel hôtelier Paul-Valéry ont des idées. Afin de pallier la faiblesse des moyens de l’Éducation nationale pour financer leurs voyages d’études, ils n’arrêtent pas de mobiliser les bonnes volontés à coups d’initiatives originales et qui font mouche. Après l’exemple donné par les terminales de restauration qui proposent un repas « tout citron » pour un voyage d’études à Barcelone, c’est au tour des élèves de 2nde de battre le rappel. Ceux-ci bénéficieront des retombées d’un vide grenier, organisé par le Lions club, pour boucler le budget de leur voyage d’études en Corse à la rentrée.','Quel est l’objectif des élèves de 2nde ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (498,4,29,'Les gens empilaient les objets dans les chariots de métal, avec frénésie. Ils avaient des visages sérieux, contractés, et leurs paupières battaient de façon anormalement lente. Les femmes tendaient les mains vers les étals. On aurait dit que les gens ne savaient plus ce qu’ils faisaient. Comment l’auraient-ils su ? Ce n’étaient pas eux qui saisissaient la marchandise. C’est la marchandise qui se collait d’elle-même à leurs mains, elle entrait directement dans les caddies. La nourriture n’était plus que des formes, des couleurs. Les yeux dévoraient les couleurs rouge, blanche, verte, orange, les yeux avaient faim de sphères et de pyramides, faim de plastiques lisses et de capsules de fer-blanc.','Dans cet extrait, qu’apprend-on sur les acheteurs ?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (499,4,30,'Ne pas assez dormir plusieurs nuits de suite perturbe, tout le monde s’en rend compte. Ce qui est moins visible, c’est comment cela affecte notre santé. (…) Des scientifiques ont montré que le manque de sommeil modifiait l’intensité de l’activité de plus de 700 gènes, parmi eux ceux liés au stress et à la lutte contre les maladies. Mais ils ne peuvent encore dire si ces modifications des gènes sont une réponse de court terme et sans danger à un sommeil de mauvaise qualité, un signe d’adaptation du corps à la privation de sommeil, ou un danger potentiel pour la santé.','Qu’est-ce que les scientifiques ont découvert concernant le manque de sommeil ?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (500,4,31,'Solitude, conflit avec les parents, difficultés scolaires… Les adolescents peuvent se confier sur des sites spécialisés où leur parole sera prise en compte. Fil Santé jeune a vu ses visites augmenter de 313 % ces dernières années. De l’autre côté de l’écran, animateurs et psychologues s’efforcent de maintenir le contact et de prolonger la discussion. L’entreprise est délicate puisque les regards et les gestes ne peuvent être pris en compte par le professionnel. Le réconfort naît aussi, et peut-être avant tout, des autres internautes qui vivent une situation similaire.','À quelle difficulté se heurtent les spécialistes ?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (501,4,32,'Méthode originale, la psychologie narrative propose les clés d’un nouvel art de vivre pour renoncer définitivement aux comportements susceptibles de brider notre propension au bonheur ! Cette pratique, loin de vanter le bienfait de vaines chimères, repose sur une prise de conscience : celle que le monde tel que je le pense n’est pas tel que je le vis. Le travestissement de la réalité est incessant. Il y a d’un côté la réalité des faits, et de l’autre, ma représentation, explique Yves Alexandre Thalmann. Avec notre cerveau, nous passons notre temps à organiser les liens de cause à effet de façon à ce que ça prenne une signification à nos yeux. Or, selon le psychologue, la manière dont nous appréhendons les choses détermine davantage notre qualité de vie que les événements eux-mêmes. À ce titre, nos représentations mentales ont donc la capacité de nous procurer une vie plus agréable.','Comment la perception des évènements permet-elle d’accéder au bonheur ?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (502,4,33,'« Le Fait du Roi » un roman d’A. Thonon. C’est l’histoire d’un homme qui prend l’identité d’un autre, mort, en se glissant dans sa peau, dans sa vie, dans sa maison… Rien ne sert de raconter l’intrigue de ce roman tant elle est simple et sans surprise. L’écriture de l’auteur reste cependant toujours aussi piquante et agréable à lire. Le héros principal, quant à lui, est dépeint avec une certaine profondeur.','Sur quel point porte la critique négative faite à ce livre ?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (503,4,34,'Monsieur et Madame Martin n’ont pas un emploi du temps également captivant. Quand Monsieur se rend au travail. Madame manie l’aspirateur. Quand il est au bureau, elle achète des surgelés au supermarché. Quand il se cale devant la télé, l’épouse modèle se colle aux fourneaux. Une illustration exhumée d’un manuel des années 1950 ? Non, les images d’un exercice pour une classe de CP afin de « comprendre la simultanéité » en étudiant les moments de la journée d’une famille ». Quand Virginie Sassoon est tombée sur ce document ultra-stéréotypé dans le classeur de sa fille, cette maman est tombée des nues. « Cette fiche dévoile une forme de violence symbolique qui persiste dans notre société et qui relève selon moi, de la responsabilité collective. »','Pourquoi Virginie Sassoon est-elle choquée par les exercices proposés dans la classe de sa fille ?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (504,4,35,'Des chercheurs mettent en doute l’idée répandue, que la langue que nous parlons influence notre façon de penser. Ils présentent une recherche sur l’ordre des mots dans la phrase : Sujet, Verbe, Objet pour certaines langues : Sujet, Objet, Verbe pour d’autres. Leurs 40 sujets, locuteurs d’anglais, d’espagnol, de mandarin, de turc, ont décrit des séquences vidéo dans leur langue d’abord, puis en utilisant des gestes. Si les descriptions verbales différaient dans l’ordre des mots selon les langues, les descriptions faites avec les mains reprenaient toutes le même ordre (sujet, objet, verbe), suivant celui des langues des signes inventées par des locuteurs sourds.','Quel est le résultat de l’expérience présentée dans cet article ?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (505,4,36,'Sexistes, les jeux vidéo ? Peut-être que oui, peut être que non. En tout cas, à parcourir les allées de la Paris Games Week, l’œil avisé aura lui-même bien du mal à trouver un personnage principal féminin de jeu vidéo. Il y a bien la célébrissime Lara Croft du jeu vidéo Tomb Raider, aux attributs particulièrement imposants, conçus presque sur mesure pour plaire aux masculins. Pour le reste, circulez, il n’y a -presque rien d’autre à voir, si l’on balaye d’un coup de manette de jeu, au mieux, les princesses à sauver, au pire, les call-girls de mafioso. Pourtant, l’industrie du jeu vidéo a pris conscience ces dernières années du potentiel du marché des joueuses.','Quel constat est dressé sur les jeux vidéo ?',33,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (506,4,37,'Les technologies de l’information et de la communication (TIC) sont de plus en plus utilisées et adoptées de façon variable par les établissements d’enseignement supérieur à travers le monde. Les TIC apparaissent autant comme une prestation en présence sur le campus que comme un enseignement ouvert et à distance. Les actions de l’UNESCO se concentrent sur l’aide aux États membres afin de développer des politiques durables dans le domaine des TIC dans l’enseignement supérieur. Les plans d’action et les investissements positifs en matière de TIC sont clairement bénéfiques pour les institutions d’enseignement supérieur (IES), même si les TIC n’ont pas remplacé les modes d’apprentissage ou d’enseignement classiques telles que les salles de classe.','Pourquoi peut-on dire que l’UNESCO est active dans le domaine des TIC ?',33,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (507,4,38,'Travailler avec son mari ou son petit ami, sa sœur ou sa mère n\'est pas une punition pour tout le monde ! Pour certains, c\'est même la condition du bien être professionnel. Si cette idée évoquait jadis une petite entreprise conservatrice, transmise de père en fils, aujourd\'hui, travailler en famille relève de réalités très différentes. Critères retenus : confiance, valeurs et goûts communs ; et surtout, besoin de réaliser ses projets plutôt que ceux des autres. Depuis toujours, la majorité des entreprises en France, toutes tailles confondues, sont familiales ; et de plus en plus de créations sont le fait de femmes. Ce sont d\'ailleurs des entreprises où l\'on vit mieux et qui durent plus longtemps que les autres. Aujourd\'hui, la création d\'une entreprise est plus souvent motivée par le désir d\'assurer un travail à ses enfants ou d\'échapper à des structures jugées déshumanisantes.','Que permet la structure d\'entreprise présentée ?',33,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (508,4,39,'Le contrôle, en toute matière, aboutit à pervertir l\'action... Dès qu\'une action est soumise à un contrôle, le but profond de celui qui agit n\'est plus l\'action, mais la prévision du contrôle, la mise en échec des moyens de contrôle. Le contrôle des études n\'est qu\'un cas particulier et une démonstration éclatante de cette observation très générale. Le diplôme donne à la société un fantôme de garantie, et aux diplômés des fantômes de droits. Le diplôme passe officiellement pour détenir un savoir : il garde toute sa vie ce brevet d\'une science momentanée. C\'est pour accéder au diplôme qu\'on a vu se substituer à la lecture des auteurs, l\'usage des résumés, des manuels, des recueils de questions et de réponses toutes faites et autres abominations.','Que soutient l’auteur de ce texte à propos du contrôle ?',33,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (509,5,1,'<p>Vous voulez découvrir d\'autres cultures&nbsp;?</p><p>Vous voulez parler anglais, français, espagnol&nbsp;?</p><p>Leçons à la maison ou au centre Bernardisilmo.</p><p>Informations au 01 03 02 06 65.</p>','Qu\'est-ce que propose cette publicité&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (510,5,2,'<p>Faites confiance à l\'entreprise pour tous vos envois urgents.</p><p>Nous prenons vos paquets à domicile ou dans les bureaux de poste et nous les envoyons dans le monde entier.</p>','Que propose cette entreprise&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (511,5,3,'<p>Je suis bien arrivé chez moi. Je t\'appelle demain pour aller voir le film.</p><p>Je t\'embrasse.</p><p><strong>Cristian.</strong></p>','Où est Cristian&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (512,5,4,'<p>Pierre, n\'oubliez pas notre déjeuner au restaurant.</p><p>Je vous attends devant l\'ascenseur.</p><p><strong>Alice.</strong></p>','Pourquoi est-ce qu\'Alice attend Pierre&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (513,5,5,'<p>François,</p><p>Pouvons-nous nous rencontrer dans ton bureau demain matin&nbsp;?</p><p><strong>Ariane.</strong></p>','Pourquoi Ariane écrit-elle ce message&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (514,5,6,'<p>Le forum de Paris s\'adresse aux jeunes de moins de trente ans, avec ou sans diplôme. Des milliers d\'offres sont disponibles dans près de 300 métiers. Chaque année, un grand nombre de jeunes signent un contrat de travail lors du salon.</p>','Pourquoi le forum de Paris est-il utile aux jeunes&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (515,5,7,'<p><strong>Jardin de la Fontaine</strong></p><p><em>Ouverture-Fermeture</em></p><ul><li>Du 1er septembre au 31 mars&nbsp;: 7h30-18h30</li><li>Du 1er avril au 30 juin&nbsp;: 7h30-20h30</li><li>Du 1er juillet au 31 août&nbsp;: 7h00-22h30</li></ul>','Quand peut-on se promener dans le parc après 18h30&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (516,5,8,'<ul><li>1&nbsp;kg de pommes</li><li>Salade</li><li>Mouchoirs en papier</li></ul>','Où trouve-t-on ces produits&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (517,5,9,'<p>Bonjour Ahmed,</p><p>Ce message est pour te rappeler la réunion de lundi. Nous commanderons des paniers-repas pour le midi, car la séance peut durer longtemps&nbsp;: les dossiers à traiter sont nombreux. Peux-tu en informer les personnes des services concernés&nbsp;? Merci d\'avance.</p><p>À lundi.</p><p><strong>elite tcf canada</strong></p>','Que demande elite tcf canada à Ahmed&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (518,5,10,'<p>Madame, Monsieur,</p><p>En raison de travaux rue Paul Vaillant, l\'accès à la piscine municipale se fera côté boulevard Camélinat, du 15 au 25 mars inclus. Veuillez nous excuser pour la gêne occasionnée.</p><p><strong>Le service municipal.</strong></p>','Quelle information est donnée au sujet de la piscine&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (519,5,11,'<p>Chers amis,</p><p>Nous aimerions vous avoir avec nous à notre soirée pour fêter la nouvelle année. Soyez là pour 21&nbsp;h&nbsp;00 en tenue décontractée. Nous sommes entre amis.</p><p><strong>Céline et Redah</strong></p>','Pourquoi Céline et Redah invitent-ils des amis&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (520,5,12,'<p>Clément et Pierre vont participer au tour automobile 4L Trophy au Maroc. Ils vont apporter 40&nbsp;kg de matériel et 10&nbsp;kg de nourriture à une école. Les deux amis recherchent des solutions pour payer leur voyage.</p><p>Vous voulez les aider&nbsp;?</p><p><a href=\"mailto:clp@4Ltrophy.fr\">clp@4Ltrophy.fr</a></p>','De quoi ont besoin Clément et Pierre&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (521,5,13,'<p>Chers collègues,</p><p>Veuillez rendre au plus tard vendredi midi votre feuille de demande de congés. Nous vous rappelons qu\'il est essentiel pour le bon fonctionnement de notre société pendant la période estivale et pour satisfaire toutes vos demandes que ces feuilles soient dûment complétées et remises le plus tôt possible à votre responsable. Nous vous remercions de votre collaboration et nous vous souhaitons une bonne semaine.</p><p><strong>La direction des ressources humaines.</strong></p>','Dans ce message électronique, que demande-t-on aux employés&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (522,5,14,'<p><strong>«&nbsp;L\'internaute.fr&nbsp;»</strong> vous informe sur la protection de l\'environnement.</p><p>Chaque année, c\'est environ un million de tonnes de courriers non adressés qui arrivent dans les boîtes aux lettres des Français. Ces courriers sont des publicités de supermarchés ou des journaux gratuits. Or, il vaudrait mieux limiter la production de papier inutile.</p><p>La meilleure méthode consiste à poser un autocollant «&nbsp;Stop Pub&nbsp;», disponible gratuitement sur le site du ministère de l\'Écologie. Lorsqu\'il s\'agit de courrier adressé à votre nom, vous pouvez solliciter la liste Robinson pour demander de ne plus recevoir de courrier envoyé par les listes de marketing.</p>','Quel est l\'objectif de l\'article de «&nbsp;L\'internaute.fr&nbsp;»&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (523,5,15,'<p>Des ingénieurs travaillent très sérieusement à la réalisation d\'un bus, semblable à un tramway tunnel qui circulera au-dessus des files de voitures pour dégager le trafic dans les zones urbaines. L\'engin sera entièrement électrique et pourra transporter 1&nbsp;200 personnes à une vitesse de 60&nbsp;km/heure. Pour que les automobilistes «&nbsp;au-dessous&nbsp;» évoluent sans danger, des feux placés dans la partie inférieure du bus signaleront ses changements de direction.</p>','Quel sera l\'atout de ce moyen de transport&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (524,5,16,'<p>Pas facile de trouver le juste équilibre entre respect et liberté. Le principal du lycée Charles-de-Gaulle a décidé de demander à ses élèves de ne plus porter de vêtements de sport en cours. Le principal estime que c\'est une question de respect et de propreté. Un survêtement, ce n\'est pas assez habillé pour venir au lycée. Les élèves qui n\'étaient pas du même avis n\'ont pas été acceptés en cours.</p>','Pourquoi la direction de cet établissement interdit-elle la tenue de sport en classe&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (525,5,17,'<p>Courir les 42,195&nbsp;km du marathon de Paris ne s\'improvise pas. C\'est une course qui nécessite de s\'entraîner régulièrement et d\'être capable de surmonter le «&nbsp;mur de douleur&nbsp;» qui survient chez tous les marathoniens entre le 32<sup>e</sup> et le 37<sup>e</sup> kilomètre. «&nbsp;Pour espérer terminer l\'épreuve, il faut courir depuis au moins un an et, dans les dernières semaines, faire trois à quatre heures d\'entraînement hebdomadaires réparties en autant de séances&nbsp;», insiste un organisateur de stages de préparation.</p>','Quel est le conseil de cet organisateur avant de participer au marathon&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (526,5,18,'<p>Pour trouver des personnalités sortant du lot à fort potentiel d\'évolution, un cabinet de recrutement organise des entretiens individuels sans consulter au préalable le dossier des candidats. Confrontés à une étude de cas, une discussion d\'idées ou un questionnaire croisé, ils peuvent se démarquer grâce à leur savoir-être ou à un talent particulier.</p><p>Les entretiens n\'ont pas pour enjeu de poste précis, ils visent à constituer une réserve de talents, dans laquelle il sera possible de puiser.</p>','Quelle est la méthode de recrutement retenue par le cabinet&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (527,5,19,'<p><strong>Avis de Sonia sur www.village.vacances.fr</strong></p><p>C\'était notre première expérience en Villages Vacances. Nous avons découvert un produit complet&nbsp;: hébergement, restauration, activités et services. Des activités sont prévues durant la journée pour les parents et les enfants. Notre petite Mathilde a fait gratuitement de la natation et du cheval&nbsp;!</p>','Que proposent les Villages Vacances aux enfants&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (528,5,20,'<p>Le piment d\'Espelette, qui célèbre actuellement sa fête, est probablement aujourd\'hui le produit le plus emblématique du Pays basque. Il a pourtant failli devenir un produit banal, c\'est-à-dire le contraire absolu de ce qu\'il est vraiment. Au début des années 90, on trouvait en effet et on produisait du piment, dit d\'Espelette, en Afrique du Nord, en Corse, en Espagne… bref partout où on aime ce goût puissant et peu piquant qui fait sa légitime réputation. Or, les Basques n\'aiment pas se faire voler leurs traditions. Ils ont donc obtenu en juin 2000 l\'appellation d\'origine contrôlée (AOC) interdisant tout plagiat. Aujourd\'hui, le diamant rouge d\'Espelette est particulièrement apprécié de certains grands chefs qui l\'utilisent pour faire «&nbsp;exploser&nbsp;» les saveurs.</p>','L\'appellation d\'origine contrôlée accordée au piment d\'Espelette permet aux Basques…',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (529,5,21,'<p><strong>Théo, la poupée «&nbsp;inter-affective&nbsp;».</strong></p><p>Théo a deux ans. Il mesure 52&nbsp;cm et communique spontanément avec sa maman.</p><p>Lancé par Berchet, ce robot est bourré d\'électronique et de capteurs pour interagir avec l\'enfant. Ainsi, Théo dort lorsqu\'il fait nuit, se réveille au lever du jour, réclame à manger ou à boire et même à aller au pot. Sa voix numérisée est d\'un naturel confondant. Surtout, il s\'adapte aux capacités de jeux de chaque enfant&nbsp;: plus il manifestera son désir de jouer, plus le jouet sera réactif.</p>','La voix numérisée de Théo est d\'un «&nbsp;naturel confondant&nbsp;», ce qui signifie qu\'elle…',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (530,5,22,'<p><strong>Erasmus</strong></p><p>Le programme d\'échange d\'étudiants entre les universités européennes a du plomb dans l\'aile. Au point qu\'en France près de quatre mille bourses n\'ont pas trouvé preneur. Ce phénomène n\'est pas spécifique à la France puisqu\'une baisse de dix pour cent aurait été enregistrée dans une dizaine de pays.</p><p>Toutes les études traduisent une absence de désir de mobilité chez les jeunes. Parmi les explications avancées, le coût, mais surtout une préférence marquée pour les stages en entreprise.</p><p>Voilà le grand concurrent d\'Erasmus depuis quelques années&nbsp;: l\'attention portée à l\'insertion professionnelle.</p>','Qu\'explique le texte au sujet du programme Erasmus&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (531,5,23,'<p>Savoir opter pour la bonne route n\'est pas tout. L\'ultime clé pour gagner la course de la Route du Rhum, c\'est la connaissance de soi et tout particulièrement de ses rythmes de sommeil. C\'est un des aspects les plus méconnus de la voile de compétition, mais c\'est sur la faculté de récupération que peut se jouer le podium. Ainsi, Alain Gautier reconnaît avoir perdu la dernière Route du Rhum parce qu\'il n\'a pas su, dès les premiers jours de la course, gérer correctement ses phases de repos. «&nbsp;À la fin, j\'ai manqué de lucidité et j\'ai commis des erreurs&nbsp;», avoue-t-il après sa défaite.</p>','Quel conseil donne le journaliste pour remporter la course&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (532,5,24,'<p>Le château de la Bussière est une demeure du 17<sup>e</sup> siècle située dans le Loiret. Surnommé «&nbsp;le château des pêcheurs&nbsp;», il possède des collections d\'objets rares sur la pêche. Sans oublier un superbe parc. Aujourd\'hui, ce monument est confronté à un fléau&nbsp;: un champignon ronge ses édifices. Les propriétaires ont déjà lancé une campagne de restauration, mais le champignon s\'attaque aussi à d\'autres parties du domaine.</p><p>Les maîtres des lieux souhaitent que le bâtiment retrouve son éclat en sollicitant les internautes. À partir de 15&nbsp;€, les contributeurs pourront recevoir des entrées gratuites, l\'inscription de leur nom sur une plaque dans le château ou bien encore un dîner avec les propriétaires.</p>','D\'après l\'article, à quoi les internautes sont-ils encouragés&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (533,5,25,'<p>Sandrine Mercier et Michel Fonivicn ont le voyage dans la peau. Les deux journalistes ont longtemps exploré le monde avant d\'écrire un livre ensemble. <em>Ils sont partis vivre ailleurs</em> est constitué des histoires d\'une trentaine d\'expatriés et d\'autant de destins et de trajectoires.</p><p>Les auteurs sont allés chercher des personnages tous très différents, mais toujours touchants et sincères en racontant leurs parcours lointains&nbsp;: rappel du large, les premiers pas, les déceptions, le rapport à la France, la découverte des autres… c\'est certainement ce qui unit tous ces Français du bout du monde&nbsp;; par-delà leurs différences et leurs expériences&nbsp;: une ouverture d\'esprit, une volonté de partager et au final une richesse et une joie de vivre communicatives.</p>','D\'après l\'auteur de cet article, quelle est la particularité de cet ouvrage&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (534,5,26,'<p>Longtemps délaissées, les algues semblent peu à peu séduire les consommateurs.</p><p>En raison de leur confusion avec les algues vertes qui polluent le littoral, ces légumes de mer sont parfois mal considérés. Pourtant, si les algues ne font pas encore partie de notre univers culturel alimentaire, leur consommation est en progression. «&nbsp;Les Occidentaux sont-ils prêts à en faire un produit courant&nbsp;?&nbsp;» questionne le docteur Arnaud Cacoul. Pas sûr. «&nbsp;Malgré leurs bienfaits nutritionnels, leur consommation restera sans doute limitée&nbsp;», estime ce nutritionniste.</p>','Quelle place occupent les algues en France&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (535,5,27,'<p>Depuis plusieurs années, Thierry Marc, un grand chef français, intervient pour donner des cours de cuisine en prison. Faire découvrir à ce public, contraint de vivre en milieu fermé, qu\'une profession, quelle qu\'elle soit, peut être épanouissante, est une tâche qui le passionne et nécessite très naturellement une grande énergie. Le désir de rallumer cette lueur d\'espoir, de montrer «&nbsp;qu\'après&nbsp;», il peut y avoir une réinsertion réussie et que chacun la porte en lui, est un moteur pour relever ce défi.</p>','Pourquoi Thierry Marc intervient-il dans les prisons&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (536,5,28,'<p>L\'institution scolaire devra sans cesse être défendue, ne serait-ce que parce que la «&nbsp;société civile&nbsp;» n\'aura de cesse de vouloir assujettir l\'école à ses demandes particulières. Il faut sans cesse rappeler, par exemple, que les règles de l\'école ne sont pas celles de la maison. Car l\'enfant n\'y est plus seulement un enfant, il y est un élève. À l\'école, on ne se préoccupe plus du confort et de l\'affection pour l\'enfant. On s\'adresse à l\'intelligence de l\'élève.</p><p>Le rapport maître/élève n\'est d\'ailleurs pas un rapport affectif&nbsp;: on ne demande pas à un professeur d\'être sympathique. On lui demande d\'être exigeant et juste.</p>','Quelle est l\'opinion de l\'auteur&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (537,5,29,'<p>Durant les investigations journalistiques, le recours à la caméra cachée est de plus en plus fréquent. Mais souvent, son utilisation n\'est aussi qu\'un cache-misère, un moyen de compenser l\'absence d\'informations dans les reportages, de remplir le vide par des scènes un peu spectaculaires. C\'est une manière pour certains aussi de faire des économies.</p><p>Par ailleurs, cette pratique pose une autre question&nbsp;: celle du statut de la personne filmée à son insu. La filmer en caméra cachée, n\'est-ce pas supposer qu\'elle a quelque chose à se reprocher avant d\'avoir commencé à parler&nbsp;?</p>','D\'après ce texte, pourquoi les journalistes utilisent-ils des caméras cachées&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (538,5,30,'<p>Trouver un logement dans une ville étudiante est un parcours du combattant pour un grand nombre d\'inscrits dans l\'enseignement supérieur. La barrière est parfois infranchissable. Non seulement les loyers sont élevés, mais la sélection des candidats par les propriétaires est très dure, souvent basée sur le niveau de revenus des garants. Pour lever ce frein, la caution locative étudiante (CLE) vient d\'être généralisée à l\'ensemble du territoire national après avoir été expérimentée dans quatre régions pendant un an. Avec ce dispositif, c\'est l\'État qui se porte garant du versement des loyers des étudiants en cas de non-paiement.</p>','Quel est le principal obstacle à l\'accès au logement des étudiants selon cette analyse&nbsp;?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (539,5,31,'<p>Après avoir été fermée au public pendant douze ans, la grotte préhistorique d\'Atlantica, située en Espagne, doit rouvrir ses portes, mais de manière expérimentale. Il s\'agit d\'une expérience réservée à un groupe de cinq personnes tirées au hasard parmi les visiteurs du musée du site, qui vont pouvoir contempler les peintures rupestres originales. Cette expérience se déroulera une fois par semaine pendant huit mois afin de permettre à une équipe de scientifiques d\'évaluer l\'impact des visites sur l\'ensemble du site et de donner son avis sur une réouverture complète.</p>','Qu\'évoque-t-on dans cet article&nbsp;?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (540,5,32,'<p>Pas de clash ni de portes qui claquent. À l\'issue de la deuxième conférence sociale, le gouvernement peut au moins se réjouir de ce résultat. Les représentants du patronat et des syndicats n\'ont pas applaudi à tout rompre l\'intervention du premier ministre, mais il n\'y avait pas non plus eu de fâcherie comme celle qui avait marqué la première conférence. Si certains se sont dits déçus par la minceur des annonces que le premier ministre a dévoilées ou par les zones de flou qui règnent sur plusieurs dossiers brûlants — les retraites en tête —, personne n\'a non plus eu vent de colères. Il faut dire que pendant deux jours, ministres et conseillers se sont échinés à repousser les points qui fâchent à plus tard.</p>','Quel a été l\'aboutissement de la conférence&nbsp;?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (541,5,33,'<p>«&nbsp;Des taxes vertes&nbsp;» ou taxes carbone sont envisagées pour faire face aux financements nécessaires d\'énergies non polluantes. Les mécanismes prévus dans le protocole de Kyoto concernent notamment un crédit carbone qui représente un volume d\'émission de gaz à effet de serre (GES) évité et des permis d\'émission négociables. Le crédit carbone est doté d\'une valeur marchande et s\'échange entre pays industrialisés. Un pays n\'arrivant pas à atteindre son objectif de réduction des GES pourrait acheter des crédits carbone à un autre qui aurait dépassé son objectif. Ce système a été parfois qualifié de permis à polluer, car un pays riche pourrait acheter le droit de polluer à un autre ayant réellement réduit ses émissions.</p>','Quel est le paradoxe de la taxe carbone&nbsp;?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (542,5,34,'<p>Quel visage Paris pourrait-il prendre en 2100&nbsp;? C\'est ce que le collectif d\'architectes «&nbsp;Et alors&nbsp;» a imaginé au travers de vingt cartes postales géantes, exposées à Paris. Ce qui donne un résultat surprenant, parfois utopique, parfois réaliste.</p><p>Ainsi l\'idée d\'une centrale hydrothermique pour chauffer et refroidir tout un quartier, projet de la compagnie parisienne du chauffage urbain. Des potagers «&nbsp;partagés&nbsp;» au pied des immeubles en plein centre-ville, cela ressemble plus à un clin d\'œil malicieux… Le vélo a également la part belle&nbsp;:</p><p>Les architectes imaginent des voies rapides sur les toits de Paris, au milieu de toitures végétalisées et de jardins.</p>','Quel projet est présenté comme réaliste&nbsp;?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (543,5,35,'<p>Il faut se rendre à l\'évidence&nbsp;: le «&nbsp;jour&nbsp;» n\'est plus l\'unité de temps d\'un journal. Un quotidien papier ne peut pas rivaliser avec la vitesse à laquelle les sites, les blogs, les réseaux sociaux, les journaux en ligne, les radios et télés, les «&nbsp;news&nbsp;» des grands serveurs diffusent les nouvelles du jour. Aussi, au moment où il est en kiosques, se condamne-t-il à apparaître comme «&nbsp;le journal de la veille&nbsp;», perdant progressivement ses lecteurs qui, bombardés de scoops tous azimuts, sont déçus de n\'y trouver que ce qu\'ils savent déjà.</p>','Quelle est la position de l\'auteur de l\'article&nbsp;?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (544,5,36,'<p>Un vingt-sixième album de Françoise Hardy. <em>La pluie sans parapluie</em> est forcément un événement. On sait que le public qui achète encore des disques passe volontairement à la caisse, pour montrer sa fidélité, ou simplement son envie de vibrer avec cette voix unique et si familière avec laquelle elle semble d\'ailleurs plus en confiance que jamais. Elle module, appuie, interprète, joue avec souplesse de son phrasé, alors que les aficionados se contenteraient juste de ce grain unique et révéré. C\'est un album pour ceux qui ont le temps, qui ne consomment pas la musique en tant qu\'application sonore de la vie actuelle. Il faut se retrancher pour en saisir la saveur et la goûter. Un disque comme autrefois, avec un son soigné et de l\'émotion. Mais surtout une élégance comme on n\'en fait plus&nbsp;!</p>','Selon le journaliste, quel type de public pourrait s\'intéresser au dernier album de F. Hardy&nbsp;?',33,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (545,5,37,'<p>Dans leur nouvelle collection, les éditions Nil invitent des auteurs à se livrer à un exercice épistolaire intime en écrivant une lettre pour dire l\'indicible. Le modèle est celle que Kafka rédigea à l\'intention de son père et qu\'il préféra ranger dans un tiroir tant l\'accusation portée était peu amène. Avec <em>L\'autre fille</em>, missive adressée à sa sœur aînée, morte avant sa naissance, Annie Ernaux inaugure brillamment le concept, fidèle à son écriture tranchante et analytique. Rejetant la théorie de l\'autofiction, l\'écrivain se dit fascinée par la réalité, partant à la recherche d\'une vérité sur une mort que ses parents lui ont toujours cachée. En demandant à des auteurs de se libérer d\'un vieux tourment, la collection souhaite réhabiliter un genre littéraire oublié.</p>','À quel résultat la participation à cette collection conduit-elle Annie Ernaux&nbsp;?',33,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (546,5,38,'<p>Les méfiances à l\'égard de la gratuité des transports collectifs demeurent fortes. Sans surprise, l\'Union des transports publics affiche son hostilité. Trop onéreuse, ne facilitant pas le report de la voiture vers les transports collectifs, menaçant la qualité de service, la gratuité pour tous ne répondrait pas aux objectifs de développement d\'un réseau de transport.</p><p>Selon l\'UTP, la gratuité est une «&nbsp;fausse bonne idée&nbsp;» qui «&nbsp;induit des déplacements inutiles, encourage l\'étalement urbain et prive de ressources le système de transport au moment où la clientèle augmente et où les recettes fiscales des collectivités diminuent&nbsp;». Elle lui préfère le système de tarification spéciale pour les jeunes, les sans-emplois ou les familles nombreuses.</p>','Pourquoi la gratuité des transports publics est-elle critiquée&nbsp;?',33,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (547,5,39,'<p>Depuis l\'adolescence, je fréquente assidûment les dictionnaires.</p><p>Chaque fois que je bute sur un mot, que je suis dans le flou culturel, ils m\'apportent la réponse et ouvrent de nouveaux horizons à ma curiosité en me renvoyant souvent à d\'autres ouvrages. Je possède une centaine et chacun est une bibliothèque à lui seul. Tous sont autant de béquilles de ma culture&nbsp;: par exemple, quand vous cherchez le mot juste, rien de tel qu\'un dictionnaire des synonymes&nbsp;! On ouvre un dictionnaire pour se renseigner sur une question précise comme on brasse la notice d\'un produit pharmaceutique destiné à soigner ceci ou cela et de self-service de la pensée.</p>','Pourquoi Jean-Claude aime-t-il les dictionnaires&nbsp;?',33,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (548,6,1,'<p>Chers Amis,</p><p>Nous sommes heureux de vous annoncer l\'arrivée d\'un nouveau membre dans notre famille. Il se nomme Adrien et a vu le jour le 1<sup>er</sup> septembre au matin.</p><p>Bien à vous.</p>','De quel évènement s\'agit-il&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (549,6,2,'<p>Désolée, je ne viens pas aux cours de français et je ne peux pas travailler à la bibliothèque avec toi aujourd\'hui. Je suis malade et je reste à la maison.</p><p>À bientôt,</p><p><strong>Sandra</strong></p>','Qu\'est-ce que Sandra fait&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (550,6,3,'<p>J\'ai une réunion jusqu\'à 19&nbsp;h&nbsp;30. Tu peux réserver nos places au cinéma pour un film après 20&nbsp;h&nbsp;?</p><p>Merci</p><p><strong>Lucie</strong></p>','Que veut faire Lucie après 19&nbsp;h&nbsp;30&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (551,6,4,'<p><strong>SAMEDI</strong></p><ul><li><strong>Marthe</strong>&nbsp;: 12&nbsp;h—13&nbsp;h&nbsp;: Cours de natation</li><li><strong>Djamel</strong>&nbsp;: 11&nbsp;h—13&nbsp;h&nbsp;: Révision avec Claire</li></ul><p><strong>DIMANCHE</strong></p><ul><li><strong>Marthe</strong>&nbsp;: 8&nbsp;h—9&nbsp;h&nbsp;: Course avec Claire</li><li><strong>Djamel</strong>&nbsp;: 14&nbsp;h—18&nbsp;h&nbsp;: Répétition</li></ul>','Que fait Marthe le samedi à 12 heures&nbsp;?',3,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (552,6,5,'<p>Une société de production <strong>RECHERCHE</strong> pour faire de la <strong>FIGURATION</strong> dans un film sur le thème parents/enfants, de jeunes mères confrontées à l\'éducation de leurs enfants.</p>','Que recherche la société de production&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (553,6,6,'<p><strong>À Héloïse</strong></p><p>Héloïse, quand tu viendras chez moi, pense à prendre des vêtements chauds. À la montagne, en hiver, il fait très froid&nbsp;! Je t\'ai envoyé les horaires du bus par SMS. Appelle-moi ce soir quand tu rentres du travail. Vivement les vacances&nbsp;!</p><p>Bises</p><p><strong>Sam</strong></p>','Que doit faire Héloïse&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (554,6,7,'<p>Salut Samira,</p><p>La fête du cinéma commence samedi prochain, ça t\'intéresse&nbsp;? Viens chez moi après le travail vendredi, on choisira ce qu\'on ira voir samedi ou dimanche.</p><p>Réponds-moi vite&nbsp;!</p><p><strong>Lali</strong></p>','Que veut faire Lali&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (555,6,8,'<p><strong>ÉCOLE FERRANDI</strong></p><p>Les parents peuvent venir chercher leurs enfants après les cours du matin et du soir sauf si les enfants mangent à l\'école ou s\'ils font des activités après la classe. Tous les enfants doivent avoir quitté l\'école à 18&nbsp;h.</p><p><strong>P. Guignoux</strong></p>','De quoi parle le directeur&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (556,6,9,'<p>Que puis-je dire de ce documentaire, moi qui pleure depuis tant d\'années sur le manque de saveur de ce que je mange&nbsp;? Je me rappelle du bon goût des pêches et des abricots&nbsp;! Je comprends mieux la majorité des agriculteurs&nbsp;: ils ne mangeraient pas ce qu\'ils vendent, c\'est fou&nbsp;! J\'ai apprécié d\'avoir le point de vue des différentes personnes concernées&nbsp;: agriculteurs, consommateurs, enseignants, cuisiniers.</p>','Quel est le thème du documentaire&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (557,6,10,'<p>Vous mangez italien, dansez le flamenco ou apprenez le suédois&nbsp;?</p><p>Partagez vos prises de vue (portraits, paysages, etc.) qui montrent que l\'Europe fait partie de votre vie.</p><p>Participez au concours «&nbsp;Europe en images&nbsp;».</p><p><strong>À GAGNER</strong>&nbsp;: un séjour à Bruxelles ou un atelier de cuisine.</p>','Que propose ce concours&nbsp;?',9,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (558,6,11,'<p>L\'école Jean Monnet organise sa «&nbsp;Journée Portes Ouvertes&nbsp;» samedi prochain, de 9&nbsp;h&nbsp;00 à 16&nbsp;h&nbsp;00. Tous les parents d\'élèves sont invités. Ce sera l\'occasion de rencontrer les professeurs et l\'équipe administrative qui se tiennent prêts à répondre à vos questions.</p><p><strong>La direction de l\'école J. Monnet</strong></p>','Que pourront faire les parents pendant cette journée&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (559,6,12,'<p>On savait déjà que le chocolat était bon pour la tension. Les scientifiques affirment maintenant «&nbsp;qu\'une consommation de chocolat pourrait être une stratégie efficace de protection contre les rayons du soleil&nbsp;». Pour cela, il n\'est pas nécessaire de recouvrir son corps de cacao&nbsp;: d\'après les chercheurs, il suffirait de consommer trois carrés par jour pour bénéficier des bienfaits du chocolat. Cela n\'empêche pas de se protéger avec de la crème solaire et d\'avoir une bonne alimentation.</p>','Que conseillent ces chercheurs pour se protéger du soleil&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (560,6,13,'<p>Adoptées séparément à la naissance, des jumelles indonésiennes se sont retrouvées 29 ans plus tard en Suède. Elles habitaient à 40&nbsp;km l\'une de l\'autre mais ne le savaient pas. Leurs parents adoptifs avaient été informés de leur lien de parenté mais avaient arrêté leurs recherches. C\'est un message posté sur Facebook par l\'une des jumelles qui a permis leur rencontre. Elles sont l\'une et l\'autre enseignantes&nbsp;!</p>','Qu\'est-ce que ces jumelles ont en commun&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (561,6,14,'<p>«&nbsp;Avec un Master Commerce en poche, je ne pensais pas qu\'il serait à ce point difficile de trouver mon premier emploi. Et pourtant… quel chemin semé d\'embûches&nbsp;! Tout le monde me disait «&nbsp;Ne t\'inquiète pas, dans deux ou trois mois tu auras trouvé&nbsp;!&nbsp;» Sept mois plus tard, toujours rien en vue. À 26 ans, je me retrouve sans emploi, toujours chez mes parents. L\'avenir&nbsp;? Je le vois ailleurs, je prépare activement mon départ pour l\'Angleterre.&nbsp;»</p><p>Amandine n\'est pas une exception chez les jeunes. Les diplômes ne suffisent plus à assurer une situation stable en France et beaucoup de jeunes décident de partir à l\'étranger pour obtenir un emploi.</p>','De quoi est-il question dans cet article&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (562,6,15,'<p><strong>Pour ou contre les devoirs&nbsp;?</strong></p><p>Une école donne sa réponse en accueillant chaque lundi, de 17 à 18 heures, les élèves qui peuvent revenir en classe faire leurs devoirs avec leur enseignant… et leurs parents. Ainsi, un dialogue s\'instaure entre enseignants, parents et élèves. Le directeur relève un autre avantage&nbsp;: les devoirs sont bien faits. Mais les devoirs alourdissent des journées déjà longues. Avec six heures de cours, quatre jours par semaine, l\'écolier français décroche la première place sur le podium de la fatigue.</p>','Que propose cette école&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (563,6,16,'<p>Pour permettre à tous un accès égal au sport, la maison départementale des personnes handicapées offre d\'accompagner ceux qui sont en situation de handicap dans leurs projets de loisirs sportifs. Ce service propose une aide dans le choix d\'une activité, la recherche de clubs capables de les accueillir et si besoin, un accompagnement dans le premier contact avec l\'association. Il s\'agit de partir des besoins, des envies et des possibilités de la personne, pour construire avec elle son projet sportif adapté.</p>','Que propose la maison départementale&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (564,6,17,'<p><strong>COMMENT APPRENDRE UNE LANGUE ÉTRANGÈRE</strong></p><p>Existe-t-il un âge critique au-delà duquel on ne peut plus jamais atteindre le niveau d\'un locuteur natif&nbsp;? Ce sujet fait l\'objet de nombreux débats. Plus on est jeune, plus on a d\'appétit pour découvrir le monde. L\'apprentissage d\'une langue, quelle qu\'elle soit, est donc plus simple, mais il y a également une composante sociale. On se comporte avec l\'enfant d\'une manière bien particulière, que l\'on ne peut reproduire avec un adolescent ou un adulte.</p>','D\'après cet extrait, qu\'est-ce qui favorise chez les enfants l\'apprentissage d\'une langue étrangère&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (565,6,18,'<p>La question de l\'orientation est fondamentale et se pose inévitablement au moment de commencer des études universitaires. Comment faire le bon choix&nbsp;? Sur quelles bases&nbsp;? Quel parcours sera le mieux adapté à la personnalité scolaire et psychologique, aux capacités de l\'étudiant&nbsp;? Un livre, édité par le magazine <em>l\'Étudiant</em>, propose une démarche progressive qui aide à définir un projet en fonction des goûts et d\'un objectif professionnel.</p>','Que peut-on trouver dans ce livre&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (566,6,19,'<p>Madame Mansion,</p><p>Suite à notre conversation téléphonique pour le travail de secrétaire, nous aimerions vous rencontrer jeudi prochain à 10&nbsp;h&nbsp;00 dans nos bureaux. Il faudra apporter une photocopie de votre carte d\'identité et de vos diplômes. Merci de nous rappeler pour confirmer.</p><p>Cordialement,</p><p><strong>Mathieu Leroux</strong><br>Directeur du service des ressources humaines</p>','Que doit faire Mme Mansion&nbsp;?',15,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (567,6,20,'<p>Chers Valérie et Serge,</p><p>Que vos projets immobiliers voient enfin le jour avec cette année qui débute&nbsp;! Qu\'elle vous apporte la joie de déménager à Nancy comme vous le souhaitez, mais aussi, à tous les niveaux, réussite et beaucoup de bonheur&nbsp;!</p><p>J\'espère que nous aurons le temps de nous voir plus souvent et de partir à nouveau en vacances ensemble&nbsp;: notre séjour en Corse reste un merveilleux souvenir pour moi.</p><p>Je vous embrasse,</p><p><strong>Elisa</strong></p>','Quel est le but de cette lettre&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (568,6,21,'<p>Les bons vieux bancs verts sur les trottoirs parisiens ont de la concurrence. Depuis le mois de décembre, sur certains boulevards, un nouveau mobilier urbain a fait son apparition, avec 12 modèles de banquettes, chaises et tabourets. Pour la première fois, la ville de Paris recueille l\'avis des usagers et des riverains. Le traditionnel banc en fonte et bois a-t-il encore de l\'avenir au milieu de ce mobilier futuriste&nbsp;?</p>','Quelle est l\'originalité de ce projet&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (569,6,22,'<p>Le smartphone participe à l\'entretien d\'un lien pathologique de plus en plus répandu, le désir de mainmise des parents sur les adolescents. La crise d\'adolescence confronte les parents au désir d\'autonomie de l\'adolescent et les oblige à faire le deuil de leur position de parent. Cela suppose qu\'ils lâchent prise et fassent confiance à leur enfant. Mais de plus en plus de parents souhaitent que leur ado reste à la maison. Le smartphone, qui permet de rester en lien avec ses copains, arrange donc les parents.</p>','Quel est le constat fait par l\'auteur à propos des smartphones&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (570,6,23,'<p><strong>Les Arts Premiers au Musée</strong></p><p>Si cette reconnaissance sonne comme un cri de victoire, c\'est qu\'elle marque l\'issue d\'un combat idéaliste qui n\'a fait d\'autres victimes que l\'arrogance et les préjugés. Le signal en fut donné par Guillaume Apollinaire en 1909&nbsp;: «&nbsp;le Louvre devrait recueillir certains chefs-d\'œuvre exotiques dont l\'aspect n\'est pas moins émouvant que celui des beaux spécimens de la statuaire occidentale.&nbsp;» Près d\'un siècle plus tard, le vœu du poète est enfin comblé&nbsp;: plus d\'une centaine de sculptures primitives d\'Afrique, d\'Asie, d\'Océanie et des Amériques, jusqu\'alors confinées dans des réserves ethnographiques, prennent place dans le temps de l\'Art, jusqu\'alors réservé à l\'Europe et à ses sources.</p>','Cet événement est présenté comme…',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (571,6,24,'<p>Quelles sont les forces dont disposait l\'Homme pour conquérir l\'hégémonie sur la planète&nbsp;?</p><p>L\'Homme est dépourvu de moyens physiques, il n\'a ni crocs, ni griffes, ni armure&nbsp;; il est chétif, fragile et vulnérable. Mais, d\'une part, il prime tous ses autres compagnons de vie par la puissance de son cerveau&nbsp;; d\'autre part, il est attiré par ses semblables, il tend à faire groupe avec les autres individus de son espèce, et ce sont ces tendances sociales qui, multipliant l\'Homme par lui-même, lui ont donné le moyen d\'atteindre à de si prodigieux résultats dans le domaine du savoir comme dans celui du pouvoir.</p>','Qu\'est-ce qui a permis à l\'espèce humaine de conquérir le monde, à part son intelligence&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (572,6,25,'<p>Le témoignage de Maud est très représentatif de la vie étudiante actuelle&nbsp;:</p><p>«&nbsp;J\'ai cherché un logement près de la fac. J\'ai trouvé un studio à 600&nbsp;$ par mois. Mon père me donne 500 par mois. Je dois travailler comme surveillante dans un lycée. Les fins de mois sont difficiles, mais mon dossier d\'allocation logement vient d\'être accepté. Finalement&nbsp;? J\'ai de la chance&nbsp;!&nbsp;»</p>','Pourquoi Maud pense-t-elle avoir de la chance&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (573,6,26,'<p>Le rapport de l\'Agence internationale de l\'énergie se concentre sur les données de la dernière conférence climatique. Il contient une information intéressante&nbsp;: d\'après l\'agence, les réserves mondiales de gaz sont plus importantes que prévues. Le marché mondial serait même sous la menace d\'un excédent massif, en raison de l\'essor de la production américaine et d\'une chute de la demande liée à la crise.</p>','Qu\'a révélé le rapport de l\'agence internationale de l\'énergie&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (574,6,27,'<p>Une étude récente révèle que la concentration de déchets plastiques flottant à la surface du Pacifique nord a été multipliée par cent en quarante ans. Ce constat, émis par les pêcheurs en haute mer, est alarmant car cette pollution a des conséquences écologiques. La gigantesque plaque de déchets flottant sur l\'océan Pacifique, épaisse par endroits de plusieurs dizaines de mètres, constitue un milieu favorable à la reproduction d\'une espèce d\'araignée d\'eau. Cet insecte est en train de se multiplier dans le Pacifique nord. Si la densité des plastiques continue à augmenter, certaines espèces pourraient continuer à se multiplier, risquant de déséquilibrer l\'écosystème du Pacifique.</p>','Quel danger représentent ces déchets&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (575,6,28,'<p>Avez-vous déjà observé des familles en train de remplir des sachets de bonbons sur un stand de confiserie&nbsp;? Un chercheur américain a montré qu\'elles en achètent plus quand les bonbons sont de couleurs différentes. De nombreuses observations similaires prouvent que les entreprises agroalimentaires connaissent nos comportements et la manière dont nous prenons certaines de nos décisions. Par exemple, elles exploitent notre préférence innée pour le sucre, à tous les âges. Elles savent que l\'éducation nutritionnelle des enfants et des jeunes est défaillante dans certaines familles et en profitent.</p>','Que dénonce l\'auteur de cet article&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (576,6,29,'<p>L\'étendue et la variété des invités reçus par le Parlement Européen ne cessent d\'étonner. Prix Nobel, stars de série télé, grand maître des échecs… Cette diversité n\'a d\'égale que l\'éclectisme des sujets préparés et débattus au sein de l\'hémicycle&nbsp;: la situation dans des pays en guerre, les relations entre pays, les changements climatiques… Bien évidemment, ces personnalités connues et reconnues ne sont pas choisies pour les paillettes et le strass qu\'elles peuvent, parfois, véhiculer, mais parce qu\'elles ont une expertise reconnue ou un message à délivrer.</p>','À quoi réfère le terme «&nbsp;diversité&nbsp;» dans le texte&nbsp;?',21,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (577,6,30,'<p>Parcourir les routes d\'Europe l\'été, beaucoup de touristes le font sans forcément connaître les règles en vigueur dans chacun des pays. Ce qu\'il faut savoir, c\'est qu\'il existe des différences qui peuvent être notables selon les législations. Alors que la vitesse maximale sur autoroute est de 130&nbsp;km/h en France, elle n\'est que de 120&nbsp;km/h en Belgique, en Espagne ou au Portugal. Quant au taux d\'alcoolémie toléré, il varie de 0,8&nbsp;g/l en Irlande à zéro en République tchèque.</p>','Que fait l\'auteur de cet article&nbsp;?',26,'2026-07-22 23:02:08');
INSERT INTO `tcf_ce_questions` (`id`, `exam_id`, `sort_order`, `situation`, `question_text`, `points`, `created_at`) VALUES (578,6,31,'<p>On s\'est habitué depuis belle lurette à ne plus rencontrer de poinçonneurs dans le métro ni de pompistes dans les stations-service. Mais la liste des professions en voie de disparition ne cesse de s\'allonger. Caissières dans les supermarchés, guichetiers dans les banques, hôtesses dans les cinémas… Tous remplacés par des machines&nbsp;? Pas si simple. Comme l\'analyse Thibaut Carpentier, directeur du cabinet de conseil Obstand, la tentation industrielle de réduire les frais de personnel est grande mais cette logique se heurte à celle des consommateurs qui ont du mal à se passer d\'une personne humaine. D\'ailleurs, toutes les entreprises concernées l\'ont bien compris&nbsp;: pas de suppression de postes mais des redéploiements avec élargissement des compétences.</p>','Quel obstacle rencontre l\'automatisation des services&nbsp;?',26,'2026-07-22 23:02:08');
